var M=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"],WD=[],TD=[],TP=[];
function ft(m){if(!m)return"-";var h=Math.floor(m/60),mi=Math.round(m%60);return h>0?h+"h "+mi+"m":mi+"m";}
function ts(d){return fm(d.getFullYear(),d.getMonth()+1,d.getDate());}
function cm(){document.getElementById("m").classList.remove("s");}
function fm(y,m,d){return y+"-"+(m<10?"0":"")+m+"-"+(d<10?"0":"")+d;}function ld(d){return fm(d.getFullYear(),d.getMonth()+1,d.getDate());}
function fp(t,a){if(t==="Run"||t==="TrailRun"){if(a>0){var p=16.6667/a,mi=Math.floor(p),se=Math.round((p-mi)*60);return mi+":"+(se<10?"0":"")+se+" /km";}}if(t==="Swim")return(1000/a/60).toFixed(1)+" min/100m";return(a*3.6).toFixed(1)+" km/h";}
function sa(a){var d=new Date(a.s),c=document.getElementById("mc");var h="<h3>"+a.n+"</h3>";h+='<div class="r"><span class="l">Date</span><span class="v">'+d.toLocaleDateString("en-US",{weekday:"short",month:"short",day:"numeric",year:"numeric"})+'</span></div>';h+='<div class="r"><span class="l">Type</span><span class="v">'+a.t+'</span></div>';if(a.d>0)h+='<div class="r"><span class="l">Dist</span><span class="v">'+(a.d/1000).toFixed(2)+' km</span></div>';if(a.m>0)h+='<div class="r"><span class="l">Time</span><span class="v">'+ft(a.m/60)+'</span></div>';if(a.h)h+='<div class="r"><span class="l">HR</span><span class="v">'+Math.round(a.h)+' bpm</span></div>';if(a.p>0)h+='<div class="r"><span class="l">Pace</span><span class="v">'+fp(a.t,a.p)+'</span></div>';if(a.u>0)h+='<div class="r"><span class="l">Suffer</span><span class="v">'+a.u+'</span></div>';if(a.wx&&a.wx.temp!=null)h+='<div class="r"><span class="l">Weather</span><span class="v">🌡 '+a.wx.temp+'°C  💧 '+a.wx.humidity+'%  💨 '+Math.round(a.wx.wind)+' km/h</span></div>';h+='<button class="mc" onclick="cm()">Close</button>';c.innerHTML=h;c.parentElement.classList.add("s");}
function ss(s,p,d){var c=document.getElementById("mc");var h="<h3>"+s[0]+" - "+s[1]+"</h3>";if(d){var dd=new Date(d+"T00:00:00");h+='<div class="r"><span class="l">Date</span><span class="v">'+dd.toLocaleDateString("en-US",{weekday:"short",month:"short",day:"numeric",year:"numeric"})+'</span></div>';}h+='<div class="r"><span class="l">Type</span><span class="v">'+s[0]+'</span></div>';h+='<div class="r"><span class="l">Workout</span><span class="v">'+s[1]+'</span></div>';if(s[2]&&s[2]!=="-")h+='<div class="r"><span class="l">Zone</span><span class="v">'+s[2]+'</span></div>';if(s[3]&&s[3]!=="-")h+='<div class="r"><span class="l">Dist</span><span class="v">'+s[3]+'</span></div>';if(s[4]&&s[4]!=="-")h+='<div class="r"><span class="l">Duration</span><span class="v">'+s[4]+'</span></div>';if(s[5])h+='<div class="r" style="flex-wrap:wrap"><span class="l" style="width:100%">Details</span><span class="v" style="width:100%;font-size:12px;color:var(--td)">'+s[5]+'</span></div>';h+='<div class="r"><span class="l">Phase</span><span class="v">'+p+'</span></div>';h+='<button class="mc" onclick="cm()">Close</button>';c.innerHTML=h;c.parentElement.classList.add("s");}
function src(){var c=document.getElementById("mc");var ra=getRD();var h='<h3>Races</h3><div id="race-rows">';for(var i=0;i<ra.length;i++){h+='<div class="race-row" style="margin-bottom:6px;padding:6px;background:var(--bg);border-radius:6px">';h+='<div style="display:flex;gap:4px;margin-bottom:4px"><select class="rt" style="background:var(--c);color:var(--t);border:1px solid var(--b);padding:4px;border-radius:4px;font-size:11px;width:40px"><option value="A"'+((ra[i].type||"B")==="A"?" selected":"")+'>A</option><option value="B"'+((ra[i].type||"B")==="B"?" selected":"")+'>B</option></select><input class="rn" value="'+(ra[i].name||"")+'" style="background:var(--c);color:var(--t);border:1px solid var(--b);padding:4px;border-radius:4px;font-size:11px;flex:1" placeholder="Race name"><input class="rd" type="date" value="'+(ra[i].date||"")+'" style="background:var(--c);color:var(--t);border:1px solid var(--b);padding:4px;border-radius:4px;font-size:11px"><button onclick="this.closest(\x27.race-row\x27).remove()" style="background:var(--r);color:#fff;border:none;padding:2px 6px;border-radius:3px;cursor:pointer;font-size:10px">X</button></div>';h+='<div style="display:flex;gap:4px"><input class="rdi" value="'+(ra[i].dist||"")+'" style="background:var(--c);color:var(--t);border:1px solid var(--b);padding:4px;border-radius:4px;font-size:11px;flex:1" placeholder="Distance"><input class="rtt" value="'+(ra[i].target_time||"")+'" style="background:var(--c);color:var(--t);border:1px solid var(--b);padding:4px;border-radius:4px;font-size:11px;flex:1" placeholder="Target time (e.g. 5:30:00)"></div></div>'}h+='</div>';h+='<button onclick="addRaceRow()" style="width:100%;background:var(--b);color:var(--t);border:none;padding:6px;border-radius:6px;cursor:pointer;font-size:11px;margin-bottom:12px">+ Add Race</button>';h+='<div style="display:flex;gap:8px"><button onclick="svrc()" style="background:var(--a1);color:var(--on-accent);border:none;padding:8px 16px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600;flex:1">Save</button><button onclick="rsrc()" style="background:var(--b);color:var(--t);border:none;padding:8px 16px;border-radius:6px;cursor:pointer;font-size:12px;flex:1">Clear Plan</button><button onclick="cm()" style="background:var(--c);color:var(--td);border:1px solid var(--b);padding:8px 16px;border-radius:6px;cursor:pointer;font-size:12px">Cancel</button></div>';c.innerHTML=h;document.getElementById("m").classList.add("s");}
function addRaceRow(){var d=document.getElementById("race-rows");var h='<div class="race-row" style="margin-bottom:6px;padding:6px;background:var(--bg);border-radius:6px">';h+='<div style="display:flex;gap:4px;margin-bottom:4px"><select class="rt" style="background:var(--c);color:var(--t);border:1px solid var(--b);padding:4px;border-radius:4px;font-size:11px;width:40px"><option value="B">B</option><option value="A">A</option></select><input class="rn" style="background:var(--c);color:var(--t);border:1px solid var(--b);padding:4px;border-radius:4px;font-size:11px;flex:1" placeholder="Race name"><input class="rd" type="date" style="background:var(--c);color:var(--t);border:1px solid var(--b);padding:4px;border-radius:4px;font-size:11px"><button onclick="this.closest(\x27.race-row\x27).remove()" style="background:var(--r);color:#fff;border:none;padding:2px 6px;border-radius:3px;cursor:pointer;font-size:10px">X</button></div>';h+='<div style="display:flex;gap:4px"><input class="rdi" style="background:var(--c);color:var(--t);border:1px solid var(--b);padding:4px;border-radius:4px;font-size:11px;flex:1" placeholder="Distance"><input class="rtt" style="background:var(--c);color:var(--t);border:1px solid var(--b);padding:4px;border-radius:4px;font-size:11px;flex:1" placeholder="Target time (e.g. 5:30:00)"></div></div>';d.insertAdjacentHTML("beforeend",h)}
function svrc(){var ra=[],rows=document.querySelectorAll("#race-rows .race-row");rows.forEach(function(r){var n=r.querySelector(".rn").value.trim();var d=r.querySelector(".rd").value;var t=r.querySelector(".rt").value;var di=r.querySelector(".rdi").value.trim();var tt=r.querySelector(".rtt").value.trim();if(n&&d)ra.push({name:n,date:d,type:t,dist:di,target_time:tt})});var old=TP&&TP.length>0;sRD(ra);cm();ACLoaded=false;TP=[];AIPlanning=false;AICommentary="";renderCalendar(ACM||new Date().getMonth(),ACY||new Date().getFullYear());if(old&&typeof _cache!=="undefined"&&_cache.homeLat){setTimeout(function(){aiPlan()},500)}}
function rsrc(){cm();TP=[];AIPlanning=false;AICommentary="";ACLoaded=true;if(typeof _cache!=="undefined"){_cache.aiPlan=null;_cache.aiCommentary=""}if(typeof sbSaveAIPlan==="function"){sbSaveAIPlan([],"","")}renderCalendar(ACM||new Date().getMonth(),ACY||new Date().getFullYear())}
function getRD(){return sbGetRD()}
function sRD(d){sbSaveRaces(d)}
function getAK(){return sbGetAPIKey()}
function getAU(){return sbGetAPIUrl()}
function getAM(){return sbGetAPIModel()}
function spinner(sz){var c=sz==="lg"?"spinner-lg":sz==="sm"?"spinner-sm":"spinner";return'<div class="'+c+'"></div>'}
function getChartColors(){var s=getComputedStyle(document.body);return{td:s.getPropertyValue("--td").trim()||"#9e9e9e",b:s.getPropertyValue("--b").trim()||"rgba(255,255,255,0.08)",bg:s.getPropertyValue("--bg").trim()||"#000000"}}
function getHomeLocation(){if(_cache.homeLat&&_cache.homeLng)return{lat:_cache.homeLat,lng:_cache.homeLng};var locs={};for(var i=0;i<A.length;i++){var a=A[i];if(a.lat!=null&&a.lng!=null){var k=Math.round(a.lat*100)/100+","+Math.round(a.lng*100)/100;if(!locs[k])locs[k]=0;locs[k]++}}var best=null,bc=0;Object.keys(locs).forEach(function(k){if(locs[k]>bc){bc=locs[k];best=k}});if(best){var p=best.split(",");_cache.homeLat=parseFloat(p[0]);_cache.homeLng=parseFloat(p[1]);return{lat:_cache.homeLat,lng:_cache.homeLng}}return null}
async function fetchWeatherForecast(){var hl=getHomeLocation();if(!hl)return null;try{var url="https://api.open-meteo.com/v1/forecast?latitude="+hl.lat+"&longitude="+hl.lng+"&daily=temperature_2m_max,temperature_2m_min,weather_code,wind_speed_10m_max,precipitation_sum,precipitation_probability_max&forecast_days=7&timezone=auto";var r=await fetch(url);if(!r.ok)return null;var d=await r.json();var fc=[];for(var i=0;i<d.daily.time.length;i++){fc.push({date:d.daily.time[i],tempMax:d.daily.temperature_2m_max[i],tempMin:d.daily.temperature_2m_min[i],wind:d.daily.wind_speed_10m_max[i],rain:d.daily.precipitation_sum[i],rainProb:d.daily.precipitation_probability_max[i],code:d.daily.weather_code[i]})}return fc}catch(e){return null}}
async function loadForecast(){if(!_cache.forecast){var fc=await fetchWeatherForecast();if(fc)_cache.forecast=fc}}
function getForecastForDate(ds){if(!_cache.forecast)return null;for(var i=0;i<_cache.forecast.length;i++){if(_cache.forecast[i].date===ds)return _cache.forecast[i]}return null}
function fcHTML(f){if(!f)return"";var h="";h+='<span>🌡 '+f.tempMin+'°-'+f.tempMax+'°</span>';h+='<span>💨 '+f.wind+' km/h</span>';if(f.rain>0)h+='<span>🌧 '+f.rain+'mm</span>';else if(f.rainProb>50)h+='<span>🌧 '+f.rainProb+'%</span>';return h}
var obCurrent=0,obTotal=5,obRaces=[],obDetected=[];
function obRenderDots(){var dots=document.querySelectorAll("#onboard-screen .ob-dots");for(var i=0;i<dots.length;i++){var h="";for(var j=0;j<obTotal;j++){h+='<span class="ob-dot'+(j===obCurrent?' active':'')+'"></span>'}dots[i].innerHTML=h}}
function obGoTo(n){obCurrent=n;var pages=document.querySelectorAll("#onboard-screen .ob-page");for(var i=0;i<pages.length;i++){pages[i].classList.toggle("active",i===obCurrent)}obRenderDots();if(n===2)obDetectAndShow();if(n===3)obRenderRacePreview()}
function obNext(){if(obCurrent<obTotal-1)obGoTo(obCurrent+1)}
function obStart(){obCurrent=0;obRaces=[];obDetected=[];document.getElementById("onboard-screen").classList.add("active");if(document.getElementById("app-screen"))document.getElementById("app-screen").style.display="none";obGoTo(0)}
function obFinish(){document.getElementById("onboard-screen").classList.remove("active");localStorage.setItem("fitness-ai-onboarded","1");if(SB_USER){showApp()}else{document.getElementById("auth-screen").style.display="flex"}}
function obSkipAll(){localStorage.setItem("fitness-ai-onboarded","1");obFinish()}
function obNeeded(){return localStorage.getItem("fitness-ai-onboarded")!=="1"}
function obConnectIntervals(){var k=document.getElementById("ob-ii-apikey").value.trim();var a=document.getElementById("ob-ii-athlete-id").value.trim();if(!k||!a){alert("Please enter both your Intervals.icu API Key and Athlete ID.");return}sbSaveIntervalsSettings(k,a);sbSyncIntervals().then(function(n){if(n){document.getElementById("ob-intervals-status").style.display="block";document.getElementById("ob-intervals-status").textContent="✓ Connected! Synced "+n+" activities";setTimeout(function(){obNext()},800)}else{alert("No activities found. Check your API key and Athlete ID.")}}).catch(function(e){alert("Connection failed: "+e.message)})}

// Auto-detect routines for onboarding
function obDetectAndShow(){
  var patterns={};
  A.forEach(function(a){var d=new Date(a.s);var dow=d.getDay();var sm=d.getHours()*60+d.getMinutes();var em=sm+(a.m||0)/60;var h2=Math.round(sm/60);var sh=Math.round(em/60);var t=(a.t||"").replace("Virtual","").replace("Training","");var lk=(a.n||"").split(/[,\-—]/)[0].trim().substring(0,20);var k=dow+"|"+h2+"|"+sh+"|"+t+"|"+lk;if(!patterns[k])patterns[k]={dow:dow,hour:h2,type:t,location:lk,count:0,names:{}};patterns[k].count++;var sn2=a.n?String(a.n).substring(0,25):"";if(sn2)patterns[k].names[sn2]=patterns[k].names[sn2]||0;patterns[k].names[sn2]++});
  obDetected=[];
  Object.keys(patterns).forEach(function(k){var p=patterns[k];if(p.count>10){var bn=Object.keys(p.names).sort(function(a,b){return p.names[b]-p.names[a]})[0];obDetected.push({name:bn||p.type+" Club",type:p.type,day_of_week:p.dow,time_str:(p.hour<10?"0":"")+p.hour+":00",zone:"Z2",note:p.location||"",count:p.count})}});
  obDetected.sort(function(a,b){return a.day_of_week-b.day_of_week||a.time_str.localeCompare(b.time_str)});
  var list=document.getElementById("ob-routines-list");if(!list)return;
  var h="";var dns=["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
  if(obDetected.length===0){h='<div style="text-align:center;color:var(--td);padding:20px;font-size:13px">No strong patterns detected yet. You can add routines later in Settings.</div>'}
  else{for(var i=0;i<obDetected.length;i++){var r=obDetected[i];h+='<label class="ob-routine-item"><input type="checkbox" checked onchange="obDetected['+i+'].checked=this.checked"><span>'+dns[r.day_of_week]+'</span><span style="font-weight:600">'+r.name+'</span><span style="color:var(--td);font-size:11px;margin-left:auto">'+r.time_str+'</span><span style="color:var(--td);font-size:10px">('+r.count+'x)</span></label>'}}
  list.innerHTML=h;
}

function obSaveRoutines(){
  var sel=[];for(var i=0;i<obDetected.length;i++){if(obDetected[i].checked!==false)sel.push(obDetected[i])}
  if(sel.length>0){var ex=sbGetRoutines();for(var i=0;i<sel.length;i++){var dup=ex.some(function(r){return r.day_of_week===sel[i].day_of_week&&r.time_str===sel[i].time_str&&r.type===sel[i].type});if(!dup)ex.push(sel[i])}sbSaveRoutines(ex)}
  obNext()
}

function obAddRace(){var t=document.getElementById("ob-race-type").value;var n=document.getElementById("ob-race-name").value.trim();var d=document.getElementById("ob-race-date").value;var di=document.getElementById("ob-race-dist").value.trim();if(!n||!d)return;obRaces.push({name:n,date:d,type:t,dist:di});document.getElementById("ob-race-name").value="";document.getElementById("ob-race-date").value="";document.getElementById("ob-race-dist").value="";obRenderRacePreview()}
function obRenderRacePreview(){var c=document.getElementById("ob-races-preview");if(!c)return;var h="";for(var i=0;i<obRaces.length;i++){var r=obRaces[i];h+='<div style="display:flex;align-items:center;gap:8px;padding:6px 0;font-size:12px;border-bottom:1px solid var(--border)"><span style="font-weight:700;color:'+(r.type==="A"?"var(--a1)":"var(--a3)")+'">'+r.type+'-Race</span><span>'+r.name+'</span><span style="color:var(--td);margin-left:auto">'+r.date+'</span><span style="color:var(--r);cursor:pointer;font-size:14px" onclick="obRaces.splice('+i+',1);obRenderRacePreview()">×</span></div>'}c.innerHTML=h}
function obSaveRaces(){if(obRaces.length>0){var ex2=sbGetRD();for(var i=0;i<obRaces.length;i++)ex2.push(obRaces[i]);sbSaveRaces(ex2)}obNext()}
function obSaveAPI(){var k=document.getElementById("ob-apikey").value.trim();var u=document.getElementById("ob-apiurl").value.trim();var m=document.getElementById("ob-apimodel").value.trim();if(k)sbSaveAPISettings(k,u,m);obNext()}

