function cw(){var w=[],s=A.slice();s.sort(function(x,y){return new Date(x.s)-new Date(y.s)});if(!s.length)return w;var f=new Date(s[0].s),l=new Date(s[s.length-1].s),st=new Date(f);st.setDate(st.getDate()-st.getDay());var c=new Date(st);while(c<=l){var ws=new Date(c),we=new Date(c);we.setDate(we.getDate()+6);var wa=[],sp={},td=0,tt=0,mh=0;s.forEach(function(a){var ad=new Date(a.s);if(ad>=ws&&ad<=we){wa.push(a);var k=a.t;if(!sp[k])sp[k]=0;sp[k]+=(a.d||0)/1000;td+=(a.d||0)/1000;tt+=(a.m||0)/3600;if(a.x>mh)mh=a.x}});w.push({w:ws.toISOString(),a:wa,sp:sp,td:td,tt:tt,mh:mh});c.setDate(c.getDate()+7)}return w;}
function estTSS(a){if(a.u&&a.u>0)return a.u;var t=a.m/3600;if(t<=0||!t)return 0;var hr=a.h>0?a.h:0,restHR=45,lthr=170;var ifVal;if(hr>0){ifVal=(hr-restHR)/(lthr-restHR)}else{var type=a.t||"";if(type==="Run"||type==="TrailRun")ifVal=0.85;else if(type==="Ride"||type==="VirtualRide")ifVal=0.75;else if(type==="Swim")ifVal=0.8;else ifVal=0.6}ifVal=Math.min(Math.max(ifVal,0.3),1.2);var tss=t*ifVal*ifVal*100;return Math.round(tss*10)/10;}
function cf(){var s=A.slice();s.sort(function(x,y){return new Date(x.s)-new Date(y.s)});if(s.length<2)return{t:[],l:{c:0,a:0,t:0}};var daily={};s.forEach(function(a){var d=a.s.substring(0,10);if(!daily[d])daily[d]={d:d,tss:0};daily[d].tss+=estTSS(a)});var keys=Object.keys(daily).sort();var data=[];var ctl=0,atl=0;var wC=1-Math.exp(-1/42);var wA=1-Math.exp(-1/7);var first=keys[0];var prevDate=new Date(first+"T00:00:00Z");for(var di=0;di<keys.length;di++){var curDate=new Date(keys[di]+"T00:00:00Z");var gapDays=Math.round((curDate-prevDate)/86400000);if(di>0&&gapDays>1){for(var g=1;g<gapDays;g++){ctl=ctl*(1-wC);atl=atl*(1-wA);data.push({d:ts(new Date(prevDate.getTime()+g*86400000)),c:Math.round(ctl*10)/10,a:Math.round(atl*10)/10,t:Math.round((ctl-atl)*10)/10})}}ctl=ctl*(1-wC)+daily[keys[di]].tss*wC;atl=atl*(1-wA)+daily[keys[di]].tss*wA;data.push({d:ts(curDate),c:Math.round(ctl*10)/10,a:Math.round(atl*10)/10,t:Math.round((ctl-atl)*10)/10});prevDate=curDate}var l=data[data.length-1];return{t:data,l:l}}
