var AI_PHASE_NAMES=["Race","Peak","Build","Base","Prep","Transition"];

function computePhaseForDate(dateStr,aRaceDateStr,atpPhases){
  if(atpPhases&&Array.isArray(atpPhases)){
    for(var i=0;i<atpPhases.length;i++){
      if(dateStr>=atpPhases[i].start&&dateStr<=atpPhases[i].end)return i;
    }
  }
  var wks=Math.round((new Date(aRaceDateStr)-new Date(dateStr+"T00:00:00"))/604800000);
  if(wks<=1)return 0;if(wks<=2)return 1;if(wks<=6)return 2;
  if(wks<=12)return 3;if(wks<=24)return 4;return 5;
}

