function saveRoutineSettings(){
  var routines=[];
  var rows=document.querySelectorAll("#routine-rows .routine-row");
  rows.forEach(function(r){
    var n=r.querySelector(".rn").value.trim();
    if(!n)return;
    routines.push({
      name:n,
      type:r.querySelector(".rt").value,
      day_of_week:parseInt(r.querySelector(".rdow").value),
      time_str:r.querySelector(".rtime").value.trim(),
      zone:r.querySelector(".rzone").value.trim()||"Z2",
      note:r.querySelector(".rnote").value.trim()
    });
  });
  sbSaveRoutines(routines);
  cm();
  ACLoaded=false;
  renderCalendar(ACM||new Date().getMonth(),ACY||new Date().getFullYear());
}

function autoDetectRoutines(){
  var patterns={};
  A.forEach(function(a){
    var d=new Date(a.s);
    var dow=d.getDay();
    var startMin=d.getHours()*60+d.getMinutes();
    var stopMin=startMin+(a.m||0)/60;
    var hour=Math.round(startMin/60);
    var stopHour=Math.round(stopMin/60);
    var t=(a.t||"").replace("Virtual","").replace("Training","");
    var locKey=(a.n||"").split(/[,\-—]/)[0].trim().substring(0,20);
    var key=dow+"|"+hour+"|"+stopHour+"|"+t+"|"+locKey;
    if(!patterns[key])patterns[key]={dow:dow,hour:hour,type:t,location:locKey,count:0,names:{}};
    patterns[key].count++;
    var shortName=a.n?String(a.n).substring(0,25):"";
    if(shortName)patterns[key].names[shortName]=patterns[key].names[shortName]||0;
    patterns[key].names[shortName]++;
  });
  var suggestions=[];
  Object.keys(patterns).forEach(function(k){
    var p=patterns[k];
    if(p.count>10){
      var bestName=Object.keys(p.names).sort(function(a,b){return p.names[b]-p.names[a]})[0];
      suggestions.push({
        name:bestName||p.type+" Club",
        type:p.type,
        day_of_week:p.dow,
        time_str:(p.hour<10?"0":"")+p.hour+":00",
        zone:"Z2",
        note:p.location||"Auto-detected: "+p.count+" sessions"
      });
    }
  });
  if(suggestions.length===0){
    alert("No patterns found with >10 occurrences. Try again after more training sessions accumulate.");
    return;
  }
  var existingRoutines=sbGetRoutines();
  suggestions.forEach(function(s){
    var dup=existingRoutines.some(function(r){return r.day_of_week===s.day_of_week&&r.time_str===s.time_str&&r.type===s.type});
    if(!dup)existingRoutines.push(s);
  });
  sbSaveRoutines(existingRoutines);
  alert("Detected "+suggestions.length+" routine(s) from past activities. Review them in the panel.");
  showRoutineSettings();
}
