function bindTabs(){
document.querySelectorAll(".tb").forEach(function(t){t.addEventListener("click",function(){
document.querySelectorAll(".tb").forEach(function(x){
x.style.background=x===t?"var(--a1)":"none";
x.style.color=x===t?"var(--on-accent)":"var(--td)"});
var tabId=this.getAttribute("data-tab");
document.querySelectorAll(".tc").forEach(function(x){
x.style.display=x.id==="tab-"+tabId?"block":"none"});
// Lazy load AI Calendar
if(tabId==="ac"&&!ACLoaded){ACLoaded=true;TP=generateTrainingPlan();renderCalendar(ACM||new Date().getMonth(),ACY||new Date().getFullYear());loadForecast().then(function(){renderCalendar(ACM||new Date().getMonth(),ACY||new Date().getFullYear())})}})})();}
